        None => Cow::Borrowed(SIMPLIFY_PROMPT),
        Some(extra) => {
            let mut s = String::with_capacity(SIMPLIFY_PROMPT.len() + 22 + extra.len());
            s.push_str(SIMPLIFY_PROMPT);
            s.push_str("\n\n## Additional Focus\n\n");
            s.push_str(extra);
            Cow::Owned(s)
        }
    }
}

